import koffi from "koffi";
import { ENetPacketFlag } from "./enums.js";
import { enetPacket, enet_packet_create, enet_packet_destroy, } from "./native/index.js";
const create = (data, flags = ENetPacketFlag.none) => {
    const packet = enet_packet_create(data, data.length, flags);
    if (!packet) {
        return null;
    }
    const packetAttributes = koffi.decode(packet, enetPacket);
    return { ...packetAttributes, data, native: packet };
};
